+  const sigA = getSignature(sequenceA);
+  const sigB = getSignature(sequenceB);
+
+  // Count matching signatures
+  let matches = 0;
+  for (let i = 0; i < numHashes; i++) {
+    if (sigA[i] === sigB[i]) {
+      matches++;
+    }
+  }
+
+  return matches / numHashes;
+}

